mapper.select:
SELECT d.id AS id, d.content_text AS content, d.written_date AS written_date, d.analysis_status AS analysis_status, (SELECT op->'insert'->>'image' FROM jsonb_array_elements(d.content::jsonb -> 'ops') WITH ORDINALITY AS t(op, ord) WHERE op->'insert'->>'image' IS NOT NULL ORDER BY ord LIMIT 1) AS thumbnail_url, (SELECT count(*)::int FROM jsonb_array_elements(d.content::jsonb -> 'ops') AS op WHERE op->'insert'->>'image' IS NOT NULL) AS image_count FROM diaries d WHERE d.user_id = #{userId} AND d.deleted_at IS NULL
AND d.id < #{cursor}
ORDER BY d.id DESC LIMIT #{limit}

SELECT EXISTS(
    SELECT 1
      FROM diaries
     WHERE id = #{id}
       AND user_id = #{userId}
       AND deleted_at IS NULL
)

SELECT DISTINCT to_char(written_date, 'YYYY-MM-DD') AS d
  FROM diaries
 WHERE user_id = #{userId}
   AND to_char(written_date, 'YYYY-MM') = #{yearMonth}
   AND deleted_at IS NULL
 ORDER BY d ASC

mapper.update:
UPDATE diaries
   SET deleted_at = now()
 WHERE id = #{id}
   AND user_id = #{userId}
   AND deleted_at IS NULL
